import geopandas as gpd

gdf = gpd.read_file('zip://docs/examples/data/04-labels.json.zip!04-labels.json')

gdf.metadata = {
    'name': 'accessibility_features'
}

return gdf

{
  "$schema": "https://vega.github.io/schema/vega-lite/v6.json",
  "data": {"name": "feature_stats"},
  "mark": "bar",
  "encoding": {
    "x": {
      "field": "label_type",
      "type": "nominal",
      "title": "Feature Type"
    },
    "y": {
      "field": "count",
      "type": "quantitative",
      "title": "Number of Features"
    },
    "color": {
      "field": "avg_severity",
      "type": "quantitative",
      "title": "Average Severity",
      "scale": {
        "scheme": "viridis"
      }
    },
    "tooltip": [
      {"field": "label_type", "type": "nominal", "title": "Feature Type"},
      {"field": "count", "type": "quantitative", "title": "Count"},
      {"field": "avg_severity", "type": "quantitative", "title": "Avg Severity", "format": ".2f"},
      {"field": "avg_agreement", "type": "quantitative", "title": "Avg Agreement", "format": ".2f"}
    ]
  }
}

{
  "$schema": "https://vega.github.io/schema/vega-lite/v6.json",
  "height": {
    "step": 14
  },
  "data": {
    "name": "neighborhood_stats"
  },
  "mark": "circle",
  "encoding": {
    "x": {
      "field": "count",
      "type": "quantitative",
      "title": "Number of Features"
    },
    "y": {
      "field": "neighborhood",
      "type": "nominal",
      "sort": "-x",
      "title": "Neighborhood",
      "axis": {
        "labelLimit": 200
      }
    },
    "size": {
      "field": "count",
      "type": "quantitative",
      "title": "Number of Features",
      "scale": {
        "range": [
          50,
          500
        ]
      }
    },
    "color": {
      "field": "avg_severity",
      "type": "quantitative",
      "title": "Average Severity",
      "scale": {
        "scheme": "viridis"
      }
    },
    "tooltip": [
      {
        "field": "neighborhood",
        "type": "nominal",
        "title": "Neighborhood"
      },
      {
        "field": "count",
        "type": "quantitative",
        "title": "Count"
      },
      {
        "field": "avg_severity",
        "type": "quantitative",
        "title": "Avg Severity",
        "format": ".2f"
      },
      {
        "field": "avg_agreement",
        "type": "quantitative",
        "title": "Avg Agreement",
        "format": ".2f"
      }
    ]
  }
}
